Dont:
class User {
  final String name; // Non-nullable - always has value
  final String? bio; // Nullable - might not have bio
  final DateTime createdAt;

  const User({required this.name, this.bio, required this.createdAt});

  String get displayBio => bio ?? 'No bio yet';
}

Code Good:
class User {
  late String name; // late everywhere
  String? email; // nullable when it should be required

  String getBio() => bio!; // Force unwrap - crashes if null
}

Dont:
extension StringX on String {
  bool get isValidEmail => RegExp(r'^[\w-\.]+@[\w-]+\.[a-z]{2,}$').hasMatch(this);
  String get capitalize => '${this[0].toUpperCase()}${substring(1)}';
}

extension ContextX on BuildContext {
  ThemeData get theme => Theme.of(this);
  TextTheme get textTheme => Theme.of(this).textTheme;
  ColorScheme get colorScheme => Theme.of(this).colorScheme;
  Size get screenSize => MediaQuery.sizeOf(this);
}

class ProductCard extends StatelessWidget {
  const ProductCard({super.key, required this.product}); // const constructor
  final Product product;

  @override
  Widget build(BuildContext context) {
    return Card(
      child: Padding(
        padding: const EdgeInsets.all(8.0), // const value
        child: Column(
          children: [
            const Icon(Icons.star, color: Colors.amber), // const widget
            Text(product.name),
          ],
        ),
      ),
    );
  }
}

Code Good:
class ProductCard extends StatelessWidget {
  ProductCard({required this.product}); // Not const

  Widget build(BuildContext context) {
    return Padding(
      padding: EdgeInsets.all(8.0), // New instance every build
      child: Icon(Icons.star), // New instance every build
    );
  }
}

