Dont:
sealed class AuthState {}
class Authenticated extends AuthState { final User user; Authenticated(this.user); }
class Unauthenticated extends AuthState {}
class Loading extends AuthState {}

// Exhaustive switch
Widget buildAuth(AuthState state) => switch (state) {
  Authenticated(user: final u) => HomeScreen(user: u),
  Unauthenticated() => const LoginScreen(),
  Loading() => const LoadingScreen(),
};

Code Good:
if (state is Authenticated) {
  return HomeScreen(user: state.user);
} else if (state is Unauthenticated) {
  return LoginScreen();
}
// Missing Loading case - no compiler warning

