// Parallel independent calls
final results = await Future.wait([
  userRepo.getProfile(userId),
  orderRepo.getOrders(userId),
  notifRepo.getCount(userId),
]);
final profile = results[0] as User;
final orders = results[1] as List<Order>;

// Or with records (Dart 3)
final (user, orders) = await (
  userRepo.getProfile(userId),
  orderRepo.getOrders(userId),
).wait;

Code Good:
// Sequential when they could be parallel
final user = await userRepo.getProfile(userId);
final orders = await orderRepo.getOrders(userId);
final notifCount = await notifRepo.getCount(userId);
// 3x slower than necessary!

