// Named record fields
typedef Pagination = ({List<Product> items, int total, bool hasMore});

Future<Pagination> getProducts(int page) async {
  final response = await api.getProducts(page: page);
  return (
    items: response.data.map(Product.fromJson).toList(),
    total: response.meta.total,
    hasMore: response.meta.currentPage < response.meta.lastPage,
  );
}

// Destructuring
final (:items, :total, :hasMore) = await getProducts(1);

Code Good:
// Return as Map
Future<Map<String, dynamic>> getProducts(int page) async {
  return {'items': items, 'total': 100, 'hasMore': true};
}
// No type safety, stringly-typed

