ListView.builder(
  itemBuilder: (context, index) {
    final item = items[index];
    return Dismissible(
      key: ValueKey(item.id), // Unique stable key
      child: ListTile(title: Text(item.name)),
    );
  },
)

// AnimatedList needs keys
AnimatedList(
  itemBuilder: (context, index, animation) {
    return SlideTransition(
      key: ValueKey(items[index].id),
      position: animation.drive(Tween(begin: Offset(1, 0), end: Offset.zero)),
      child: ItemWidget(item: items[index]),
    );
  },
)

Code Good:
Dismissible(
  key: Key(index.toString()), // Index changes when list reorders!
  child: ListTile(...),
)
// OR no key at all on dynamic lists

