mixin LoggableMixin {
  void logInfo(String message) => debugPrint('[INFO] $runtimeType: $message');
  void logError(String message, [Object? error]) => debugPrint('[ERROR] $runtimeType: $message $error');
}

mixin ValidationMixin {
  String? validateEmail(String? value) {
    if (value?.isEmpty ?? true) return 'Required';
    if (!value!.contains('@')) return 'Invalid email';
    return null;
  }
}

class LoginBloc extends Bloc<LoginEvent, LoginState> with LoggableMixin, ValidationMixin { ... }

